Using Go per your constraints. Here’s a small, concurrency-safe in-memory cache with optional per-item TTL and a background janitor to evict expired entries. No external dependencies.

package cache

import (
	"sync"
	"time"
)

type Cache struct {
	mu           sync.RWMutex
	items        map[string]entry
	defaultTTL   time.Duration
	stopCh       chan struct{}
	wg           sync.WaitGroup
	onEvict      func(key string, val any)
	cleanupEvery time.Duration
}

type entry struct {
	value     any
	expiresAt time.Time // zero means no expiration
}

// New creates a cache.
// - defaultTTL <= 0 means entries never expire by default.
// - cleanupEvery <= 0 disables background cleanup (expired entries are evicted lazily on Get).
// - onEvict (optional) is called after an entry is removed due to expiration (not on explicit Delete).
func New(defaultTTL, cleanupEvery time.Duration, onEvict func(string, any)) *Cache {
	c := &Cache{
		items:        make(map[string]entry),
		defaultTTL:   defaultTTL,
		stopCh:       make(chan struct{}),
		onEvict:      onEvict,
		cleanupEvery: cleanupEvery,
	}
	if cleanupEvery > 0 {
		c.wg.Add(1)
		go c.janitor()
	}
	return c
}

// Set stores a value with an optional TTL override.
// If ttl <= 0, the item does not expire. If not provided, defaultTTL is used.
func (c *Cache) Set(key string, val any, ttlOverride ...time.Duration) {
	ttl := c.defaultTTL
	if len(ttlOverride) > 0 {
		ttl = ttlOverride[0]
	}

	var exp time.Time
	if ttl > 0 {
		exp = time.Now().Add(ttl)
	}

	c.mu.Lock()
	c.items[key] = entry{value: val, expiresAt: exp}
	c.mu.Unlock()
}

// Get retrieves a value if present and not expired.
func (c *Cache) Get(key string) (any, bool) {
	now := time.Now()

	c.mu.RLock()
	e, ok := c.items[key]
	if !ok {
		c.mu.RUnlock()
		return nil, false
	}
	// Fast path if no expiration or not expired
	if e.expiresAt.IsZero() || now.Before(e.expiresAt) {
		val := e.value
		c.mu.RUnlock()
		return val, true
	}
	c.mu.RUnlock()

	// Expired: delete lazily
	c.mu.Lock()
	// Re-check after acquiring write lock
	e2, ok2 := c.items[key]
	if ok2 && !e2.expiresAt.IsZero() && !now.Before(e2.expiresAt) {
		delete(c.items, key)
	}
	c.mu.Unlock()
	return nil, false
}

// Delete removes a key. Returns true if the key existed.
func (c *Cache) Delete(key string) bool {
	c.mu.Lock()
	_, ok := c.items[key]
	if ok {
		delete(c.items, key)
	}
	c.mu.Unlock()
	return ok
}

// Len returns the number of items (including expired ones that haven't been cleaned yet).
func (c *Cache) Len() int {
	c.mu.RLock()
	n := len(c.items)
	c.mu.RUnlock()
	return n
}

// Close stops the background janitor (if running).
func (c *Cache) Close() {
	close(c.stopCh)
	c.wg.Wait()
}

func (c *Cache) janitor() {
	defer c.wg.Done()
	t := time.NewTicker(c.cleanupEvery)
	defer t.Stop()
	for {
		select {
		case <-t.C:
			c.evictExpired()
		case <-c.stopCh:
			return
		}
	}
}

func (c *Cache) evictExpired() {
	now := time.Now()
	var callbacks []struct {
		key string
		val any
	}

	c.mu.Lock()
	for k, e := range c.items {
		if !e.expiresAt.IsZero() && !now.Before(e.expiresAt) {
			if c.onEvict != nil {
				callbacks = append(callbacks, struct {
					key string
					val any
				}{k, e.value})
			}
			delete(c.items, k)
		}
	}
	c.mu.Unlock()

	// Invoke callbacks without holding the lock
	for _, cb := range callbacks {
		c.onEvict(cb.key, cb.val)
	}
}

Example usage:
- c := cache.New(5*time.Minute, time.Minute, nil)
- c.Set("foo", "bar") // uses default TTL
- v, ok := c.Get("foo")
- c.Delete("foo")
- c.Close() when shutting down the service
